enum OrderStatus {
  DRAFT = 'draft',
  PENDING_PAYMENT = 'pending_payment',
  PAID = 'paid',
  PROCESSING = 'processing',
  SHIPPED = 'shipped',
  DELIVERED = 'delivered',
  CANCELLED = 'cancelled',
  REFUNDED = 'refunded'
}

interface OrderItem {
  productId: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  discount: number;
}

class Order {
  private id: string;
  private customerId: string;
  private items: OrderItem[] = [];
  private status: OrderStatus;
  private shippingAddress: Address;
  private billingAddress: Address;
  private createdAt: Date;
  private updatedAt: Date;

  constructor(id: string, customerId: string, shippingAddress: Address) {
    this.id = id;
    this.customerId = customerId;
    this.status = OrderStatus.DRAFT;
    this.shippingAddress = shippingAddress;
    this.billingAddress = shippingAddress;
    this.createdAt = new Date();
    this.updatedAt = new Date();
  }

  addItem(product: Product, quantity: number): void {
    if (this.status !== OrderStatus.DRAFT) {
      throw new Error('Cannot modify order after submission');
    }

    const existingItem = this.items.find(item => item.productId === product.id);
    if (existingItem) {
      existingItem.quantity += quantity;
    } else {
      this.items.push({
        productId: product.id,
        productName: product.name,
        quantity,
        unitPrice: product.price,
        discount: 0
      });
    }
    this.touch();
  }

  calculateTotal(): number {
    return this.items.reduce((total, item) => {
      return total + (item.unitPrice * item.quantity * (1 - item.discount));
    }, 0);
  }

  submit(): void {
    if (this.items.length === 0) {
      throw new Error('Order must have at least one item');
    }
    this.status = OrderStatus.PENDING_PAYMENT;
    this.touch();
  }

  pay(paymentId: string): void {
    if (this.status !== OrderStatus.PENDING_PAYMENT) {
      throw new Error('Order is not pending payment');
    }
    this.status = OrderStatus.PAID;
    this.touch();
  }

  ship(trackingNumber: string): void {
    if (this.status !== OrderStatus.PAID) {
      throw new Error('Order must be paid before shipping');
    }
    this.status = OrderStatus.SHIPPED;
    this.touch();
  }

  cancel(reason?: string): void {
    if (this.status === OrderStatus.DELIVERED || this.status === OrderStatus.REFUNDED) {
      throw new Error('Cannot cancel delivered or refunded order');
    }
    this.status = OrderStatus.CANCELLED;
    this.touch();
  }

  private touch(): void {
    this.updatedAt = new Date();
  }

  getSnapshot(): OrderSnapshot {
    return {
      id: this.id,
      customerId: this.customerId,
      status: this.status,
      items: [...this.items],
      total: this.calculateTotal(),
      shippingAddress: this.shippingAddress,
      createdAt: this.createdAt,
      updatedAt: this.updatedAt
    };
  }
}

interface OrderSnapshot {
  id: string;
  customerId: string;
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  shippingAddress: Address;
  createdAt: Date;
  updatedAt: Date;
}

enum PaymentMethod {
  CREDIT_CARD = 'credit_card',
  DEBIT_CARD = 'debit_card',
  BANK_TRANSFER = 'bank_transfer',
  DIGITAL_WALLET = 'digital_wallet',
  CRYPTO = 'crypto'
}

enum PaymentStatus {
  PENDING = 'pending',
  AUTHORIZED = 'authorized',
  CAPTURED = 'captured',
  REFUNDED = 'refunded',
  FAILED = 'failed',
  CANCELLED = 'cancelled'
}

interface PaymentDetails {
  amount: number;
  currency: string;
  merchantId: string;
  customerId: string;
  paymentMethod: PaymentMethod;
  cardLastFour?: string;
  walletToken?: string;
}

class PaymentProcessor {
  private gateway: PaymentGateway;
  private transactionRepository: TransactionRepository;

  constructor(gateway: PaymentGateway, repository: TransactionRepository) {
    this.gateway = gateway;
    this.transactionRepository = repository;
  }

  async processPayment(details: PaymentDetails): Promise<PaymentResult> {
    this.validateDetails(details);

    const transaction = Transaction.create({
      amount: details.amount,
      currency: details.currency,
      merchantId: details.merchantId,
      customerId: details.customerId,
      paymentMethod: details.paymentMethod,
      status: PaymentStatus.PENDING
    });

    try {
      const authResult = await this.gateway.authorize(details);

      if (!authResult.success) {
        transaction.markAsFailed(authResult.errorCode, authResult.errorMessage);
        await this.transactionRepository.save(transaction);
        return { success: false, error: authResult.errorMessage };
      }

      transaction.authorize(authResult.transactionId);
      await this.transactionRepository.save(transaction);

      const captureResult = await this.gateway.capture(authResult.transactionId, details.amount);

      if (!captureResult.success) {
        transaction.captureFailed(captureResult.errorCode);
        await this.transactionRepository.save(transaction);
        return { success: false, error: captureResult.errorMessage };
      }

      transaction.capture(captureResult.transactionId);
      await this.transactionRepository.save(transaction);

      return { success: true, transactionId: captureResult.transactionId };
    } catch (error) {
      transaction.markAsFailed('SYSTEM_ERROR', error.message);
      await this.transactionRepository.save(transaction);
      throw error;
    }
  }

  async refundPayment(transactionId: string, amount?: number): Promise<PaymentResult> {
    const transaction = await this.transactionRepository.findById(transactionId);

    if (!transaction || transaction.status !== PaymentStatus.CAPTURED) {
      return { success: false, error: 'Transaction not eligible for refund' };
    }

    const refundAmount = amount ?? transaction.amount;
    const refundResult = await this.gateway.refund(transactionId, refundAmount);

    if (refundResult.success) {
      transaction.refund(refundResult.refundId, refundAmount);
      await this.transactionRepository.save(transaction);
      return { success: true, refundId: refundResult.refundId };
    }

    return { success: false, error: refundResult.errorMessage };
  }

  private validateDetails(details: PaymentDetails): void {
    if (details.amount <= 0) {
      throw new Error('Payment amount must be positive');
    }
    if (details.currency.length !== 3) {
      throw new Error('Invalid currency code');
    }
    if (details.paymentMethod === PaymentMethod.CREDIT_CARD && !details.cardLastFour) {
      throw new Error('Card last four digits required');
    }
  }
}

interface PaymentResult {
  success: boolean;
  transactionId?: string;
  refundId?: string;
  error?: string;
}

interface User {
  id: string;
  email: string;
  passwordHash: string;
  role: 'admin' | 'user' | 'moderator';
  isActive: boolean;
  lastLoginAt?: Date;
  failedLoginAttempts: number;
  lockedUntil?: Date;
}

class AuthService {
  private userRepository: UserRepository;
  private tokenService: TokenService;
  private passwordService: PasswordService;
  private rateLimiter: RateLimiter;

  async login(email: string, password: string): Promise<AuthResult> {
    if (this.rateLimiter.isRateLimited(email)) {
      return { success: false, error: 'Too many login attempts' };
    }

    const user = await this.userRepository.findByEmail(email);
    if (!user) {
      return { success: false, error: 'Invalid credentials' };
    }

    if (user.lockedUntil && user.lockedUntil > new Date()) {
      return { success: false, error: 'Account temporarily locked' };
    }

    const isValid = await this.passwordService.verify(password, user.passwordHash);
    if (!isValid) {
      user.failedLoginAttempts++;
      if (user.failedLoginAttempts >= 5) {
        user.lockedUntil = new Date(Date.now() + 15 * 60 * 1000);
      }
      await this.userRepository.update(user);
      return { success: false, error: 'Invalid credentials' };
    }

    user.failedLoginAttempts = 0;
    user.lastLoginAt = new Date();
    await this.userRepository.update(user);

    const accessToken = this.tokenService.generateAccessToken(user.id, user.role);
    const refreshToken = this.tokenService.generateRefreshToken(user.id);

    return {
      success: true,
      accessToken,
      refreshToken,
      expiresIn: 3600
    };
  }

  async refreshToken(refreshToken: string): Promise<AuthResult> {
    try {
      const payload = this.tokenService.verifyRefreshToken(refreshToken);
      const user = await this.userRepository.findById(payload.userId);

      if (!user || !user.isActive) {
        return { success: false, error: 'Invalid token' };
      }

      const newAccessToken = this.tokenService.generateAccessToken(user.id, user.role);
      const newRefreshToken = this.tokenService.generateRefreshToken(user.id);

      return {
        success: true,
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresIn: 3600
      };
    } catch (error) {
      return { success: false, error: 'Invalid refresh token' };
    }
  }

  async logout(userId: string): Promise<void> {
    await this.tokenService.revokeToken(userId);
  }
}

interface AuthResult {
  success: boolean;
  accessToken?: string;
  refreshToken?: string;
  expiresIn?: number;
  error?: string;
}

enum ContentType {
  ARTICLE = 'article',
  PAGE = 'page',
  BLOG_POST = 'blog_post',
  VIDEO = 'video',
  PODCAST = 'podcast'
}

enum ContentStatus {
  DRAFT = 'draft',
  REVIEW = 'review',
  PUBLISHED = 'published',
  ARCHIVED = 'archived',
  DELETED = 'deleted'
}

interface ContentMetadata {
  authorId: string;
  tags: string[];
  categories: string[];
  seoTitle?: string;
  seoDescription?: string;
  featuredImage?: string;
  publishDate?: Date;
}

class Content {
  private id: string;
  private title: string;
  private slug: string;
  private body: string;
  private contentType: ContentType;
  private status: ContentStatus;
  private metadata: ContentMetadata;
  private version: number;
  private createdAt: Date;
  private updatedAt: Date;

  constructor(id: string, title: string, body: string, contentType: ContentType, authorId: string) {
    this.id = id;
    this.title = title;
    this.slug = this.generateSlug(title);
    this.body = body;
    this.contentType = contentType;
    this.status = ContentStatus.DRAFT;
    this.metadata = { authorId, tags: [], categories: [] };
    this.version = 1;
    this.createdAt = new Date();
    this.updatedAt = new Date();
  }

  updateTitle(title: string): void {
    this.title = title;
    this.slug = this.generateSlug(title);
    this.touch();
  }

  updateBody(body: string): void {
    this.body = body;
    this.touch();
  }

  addTag(tag: string): void {
    if (!this.metadata.tags.includes(tag)) {
      this.metadata.tags.push(tag);
      this.touch();
    }
  }

  addCategory(category: string): void {
    if (!this.metadata.categories.includes(category)) {
      this.metadata.categories.push(category);
      this.touch();
    }
  }

  submitForReview(): void {
    if (this.status !== ContentStatus.DRAFT) {
      throw new Error('Only drafts can be submitted for review');
    }
    this.status = ContentStatus.REVIEW;
    this.touch();
  }

  publish(): void {
    if (this.status !== ContentStatus.REVIEW) {
      throw new Error('Content must be in review status');
    }
    this.status = ContentStatus.PUBLISHED;
    this.metadata.publishDate = new Date();
    this.touch();
  }

  archive(): void {
    this.status = ContentStatus.ARCHIVED;
    this.touch();
  }

  private generateSlug(title: string): string {
    return title
      .toLowerCase()
      .replace(/[^\w\s-]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-')
      .trim();
  }

  private touch(): void {
    this.updatedAt = new Date();
    this.version++;
  }

  getSnapshot(): ContentSnapshot {
    return {
      id: this.id,
      title: this.title,
      slug: this.slug,
      body: this.body,
      contentType: this.contentType,
      status: this.status,
      metadata: { ...this.metadata },
      version: this.version,
      createdAt: this.createdAt,
      updatedAt: this.updatedAt
    };
  }
}

interface ContentSnapshot {
  id: string;
  title: string;
  slug: string;
  body: string;
  contentType: ContentType;
  status: ContentStatus;
  metadata: ContentMetadata;
  version: number;
  createdAt: Date;
  updatedAt: Date;
}

interface Message {
  id: string;
  roomId: string;
  senderId: string;
  senderName: string;
  content: string;
  messageType: 'text' | 'image' | 'file' | 'system';
  timestamp: Date;
  edited: boolean;
  replyTo?: string;
  reactions: Map<string, Set<string>>;
}

class ChatRoom {
  private id: string;
  private name: string;
  private participants: Set<string> = new Set();
  private messages: Message[] = [];
  private maxMessageLength: number;
  private typingUsers: Map<string, NodeJS.Timeout> = new Map();

  constructor(id: string, name: string, maxMessageLength: number = 2000) {
    this.id = id;
    this.name = name;
    this.maxMessageLength = maxMessageLength;
  }

  join(userId: string, userName: string): void {
    if (!this.participants.has(userId)) {
      this.participants.add(userId);
      this.addSystemMessage(`${userName} joined the room`);
    }
  }

  leave(userId: string): void {
    if (this.participants.has(userId)) {
      this.participants.delete(userId);
      const user = this.getMessageSender(userId);
      if (user) {
        this.addSystemMessage(`${user} left the room`);
      }
    }
  }

  sendMessage(senderId: string, senderName: string, content: string, replyTo?: string): Message {
    if (!this.participants.has(senderId)) {
      throw new Error('User is not in the room');
    }

    if (content.trim().length === 0) {
      throw new Error('Message cannot be empty');
    }

    if (content.length > this.maxMessageLength) {
      throw new Error(`Message exceeds maximum length of ${this.maxMessageLength}`);
    }

    const message: Message = {
      id: crypto.randomUUID(),
      roomId: this.id,
      senderId,
      senderName,
      content,
      messageType: 'text',
      timestamp: new Date(),
      edited: false,
      replyTo,
      reactions: new Map()
    };

    this.messages.push(message);
    return message;
  }

  editMessage(messageId: string, senderId: string, newContent: string): void {
    const message = this.findMessage(messageId);
    if (!message || message.senderId !== senderId) {
      throw new Error('Message not found or unauthorized');
    }

    if (newContent.length > this.maxMessageLength) {
      throw new Error('Edited message exceeds maximum length');
    }

    message.content = newContent;
    message.edited = true;
  }

  addReaction(messageId: string, userId: string, emoji: string): void {
    const message = this.findMessage(messageId);
    if (!message) return;

    if (!message.reactions.has(emoji)) {
      message.reactions.set(emoji, new Set());
    }
    message.reactions.get(emoji)!.add(userId);
  }

  startTyping(userId: string): void {
    if (!this.typingUsers.has(userId)) {
      this.typingUsers.set(userId, setTimeout(() => {
        this.typingUsers.delete(userId);
      }, 3000));
    }
  }

  stopTyping(userId: string): void {
    const timeout = this.typingUsers.get(userId);
    if (timeout) {
      clearTimeout(timeout);
      this.typingUsers.delete(userId);
    }
  }

  private findMessage(messageId: string): Message | undefined {
    return this.messages.find(m => m.id === messageId);
  }

  private getMessageSender(userId: string): string | undefined {
    const message = this.messages.filter(m => m.senderId === userId).pop();
    return message?.senderName;
  }

  private addSystemMessage(content: string): void {
    this.messages.push({
      id: crypto.randomUUID(),
      roomId: this.id,
      senderId: 'system',
      senderName: 'System',
      content,
      messageType: 'system',
      timestamp: new Date(),
      edited: false,
      reactions: new Map()
    });
  }

  getMessages(limit: number = 50, before?: Date): Message[] {
    let filtered = [...this.messages];
    if (before) {
      filtered = filtered.filter(m => m.timestamp < before);
    }
    return filtered.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime()).slice(0, limit);
  }
}

export { ChatRoom, Message };

enum StockStatus {
  IN_STOCK = 'in_stock',
  LOW_STOCK = 'low_stock',
  OUT_OF_STOCK = 'out_of_stock',
  DISCONTINUED = 'discontinued'
}

interface InventoryItem {
  sku: string;
  name: string;
  quantity: number;
  reserved: number;
  reorderPoint: number;
  maxStock: number;
  warehouseId: string;
  lastUpdated: Date;
}

class InventoryManager {
  private items: Map<string, InventoryItem> = new Map();
  private warehouses: Map<string, Warehouse> = new Map();

  addItem(item: InventoryItem): void {
    if (item.quantity < 0 || item.reserved < 0) {
      throw new Error('Quantity and reserved cannot be negative');
    }
    if (item.reserved > item.quantity) {
      throw new Error('Reserved quantity cannot exceed available quantity');
    }
    this.items.set(item.sku, item);
  }

  updateQuantity(sku: string, delta: number): void {
    const item = this.items.get(sku);
    if (!item) {
      throw new Error('Item not found');
    }

    const newQuantity = item.quantity + delta;
    if (newQuantity < 0) {
      throw new Error('Insufficient stock');
    }

    item.quantity = newQuantity;
    item.lastUpdated = new Date();
  }

  reserveStock(sku: string, quantity: number): boolean {
    const item = this.items.get(sku);
    if (!item) return false;

    const available = item.quantity - item.reserved;
    if (available < quantity) {
      return false;
    }

    item.reserved += quantity;
    item.lastUpdated = new Date();
    return true;
  }

  releaseReservation(sku: string, quantity: number): void {
    const item = this.items.get(sku);
    if (!item) {
      throw new Error('Item not found');
    }

    if (item.reserved < quantity) {
      throw new Error('Cannot release more than reserved');
    }

    item.reserved -= quantity;
    item.lastUpdated = new Date();
  }

  getStatus(sku: string): StockStatus {
    const item = this.items.get(sku);
    if (!item) return StockStatus.OUT_OF_STOCK;

    if (item.quantity === 0) return StockStatus.OUT_OF_STOCK;
    if (item.quantity <= item.reorderPoint) return StockStatus.LOW_STOCK;
    return StockStatus.IN_STOCK;
  }

  getLowStockItems(): InventoryItem[] {
    return Array.from(this.items.values()).filter(item =>
      item.quantity <= item.reorderPoint && item.quantity > 0
    );
  }

  transferStock(fromWarehouse: string, toWarehouse: string, sku: string, quantity: number): void {
    const sourceItem = this.getItemInWarehouse(fromWarehouse, sku);
    const destItem = this.getItemInWarehouse(toWarehouse, sku);

    if (!sourceItem || sourceItem.quantity < quantity) {
      throw new Error('Insufficient stock in source warehouse');
    }

    if (!destItem) {
      throw new Error('Destination warehouse does not have this item');
    }

    sourceItem.quantity -= quantity;
    destItem.quantity += quantity;

    const now = new Date();
    sourceItem.lastUpdated = now;
    destItem.lastUpdated = now;
  }

  private getItemInWarehouse(warehouseId: string, sku: string): InventoryItem | undefined {
    return Array.from(this.items.values()).find(
      item => item.warehouseId === warehouseId && item.sku === sku
    );
  }
}

