enum SubscriptionPlan {
  FREE = 'free',
  BASIC = 'basic',
  PRO = 'pro',
  ENTERPRISE = 'enterprise'
}

enum BillingCycle {
  MONTHLY = 'monthly',
  QUARTERLY = 'quarterly',
  ANNUALLY = 'annually'
}

interface Plan {
  id: SubscriptionPlan;
  name: string;
  price: number;
  billingCycle: BillingCycle;
  features: string[];
  maxUsers: number;
  storageLimit: number;
}

class Subscription {
  private id: string;
  private userId: string;
  private plan: SubscriptionPlan;
  private billingCycle: BillingCycle;
  private status: 'active' | 'cancelled' | 'expired' | 'past_due';
  private currentPeriodStart: Date;
  private currentPeriodEnd: Date;
  private cancelAtPeriodEnd: boolean;
  private createdAt: Date;

  constructor(id: string, userId: string, plan: SubscriptionPlan, billingCycle: BillingCycle) {
    this.id = id;
    this.userId = userId;
    this.plan = plan;
    this.billingCycle = billingCycle;
    this.status = 'active';
    this.currentPeriodStart = new Date();
    this.currentPeriodEnd = this.calculatePeriodEnd();
    this.cancelAtPeriodEnd = false;
    this.createdAt = new Date();
  }

  private calculatePeriodEnd(): Date {
    const end = new Date(this.currentPeriodStart);
    switch (this.billingCycle) {
      case BillingCycle.MONTHLY:
        end.setMonth(end.getMonth() + 1);
        break;
      case BillingCycle.QUARTERLY:
        end.setMonth(end.getMonth() + 3);
        break;
      case BillingCycle.ANNUALLY:
        end.setFullYear(end.getFullYear() + 1);
        break;
    }
    return end;
  }

  cancel(): void {
    if (this.status !== 'active') {
      throw new Error('Subscription is not active');
    }
    this.cancelAtPeriodEnd = true;
  }

  resume(): void {
    if (this.status !== 'cancelled') {
      throw new Error('Subscription is not cancelled');
    }
    this.status = 'active';
    this.cancelAtPeriodEnd = false;
    this.currentPeriodStart = new Date();
    this.currentPeriodEnd = this.calculatePeriodEnd();
  }

  upgrade(newPlan: SubscriptionPlan): void {
    if (this.status !== 'active') {
      throw new Error('Subscription must be active to upgrade');
    }
    this.plan = newPlan;
    this.currentPeriodEnd = this.calculateProratedEnd(newPlan);
  }

  downgrade(newPlan: SubscriptionPlan): void {
    if (this.status !== 'active') {
      throw new Error('Subscription must be active to downgrade');
    }
    this.plan = newPlan;
  }

  private calculateProratedEnd(newPlan: SubscriptionPlan): Date {
    const daysRemaining = (this.currentPeriodEnd.getTime() - Date.now()) / (1000 * 60 * 60 * 24);
    const end = new Date();
    end.setDate(end.getDate() + Math.ceil(daysRemaining));
    return end;
  }

  isExpired(): boolean {
    return this.currentPeriodEnd < new Date();
  }

  getStatus(): string {
    if (this.isExpired()) return 'expired';
    if (this.cancelAtPeriodEnd) return 'cancelled';
    return this.status;
  }

  getPlanDetails(): Plan {
    return plans.find(p => p.id === this.plan)!;
  }
}

